INSERT INTO public."Epic" VALUES ('cmmpy9rzg000011nqzvc7oe8c', 'EP-PORTAL-FOUND-001', 'Portal, Portfolio, Inventory, and Workspace Surface Foundation', 'Reestablish the core platform shell and major route surfaces created during the last four days: portfolio, inventory, employee, customer, ops, platform, admin, and supporting portfolio metrics.', 'done', '2026-03-14 06:33:59.02', '2026-03-14 06:33:59.02') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmpy9rzq000111nq9mbxakax', 'EP-BACKLOG-FOUND-001', 'Backlog and Epic Management Foundation', 'Restore the foundational backlog system and epic grouping capability that was introduced to manage work across the digital product factory.', 'done', '2026-03-14 06:33:59.031', '2026-03-14 06:33:59.031') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmpy9rzz000211nqt2g9ktoe', 'EP-EA-MODEL-001', 'Enterprise Architecture Modeling Foundation and Canvas', 'Restore the EA metamodel, views, canvas, relationship handling, and structured notation groundwork added for the EA workspace.', 'in-progress', '2026-03-14 06:33:59.039', '2026-03-14 06:33:59.039') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmpy9s04000311nqqr84wgrs', 'EP-EA-REF-001', 'EA Reference Model Assessment and Reference Architecture Loading', 'Track the IT4IT-based reference model assessment foundation and the repeatable reference architecture loading path needed to create live EA models and views from repo-backed artifacts.', 'in-progress', '2026-03-14 06:33:59.044', '2026-03-14 06:33:59.044') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmpy9s0g000611nqxtc86284', 'EP-GOV-FOUND-001', 'Unified Identity, Access, and Agent Governance Foundation', 'Restore the shared human, team, delegation, and agent-governance foundation intended to support HR core, CRM, and governed AI execution.', 'in-progress', '2026-03-14 06:33:59.056', '2026-03-14 06:33:59.056') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmpy9s0k000711nqlpgehpz6', 'EP-DISCOVERY-001', 'Bootstrap Infrastructure Discovery and Portfolio Quality Foundation', 'Track the local bootstrap discovery pipeline, normalized inventory, graph projection, foundational attribution, and quality issue surfacing.', 'in-progress', '2026-03-14 06:33:59.06', '2026-03-14 06:33:59.06') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmpy9s0o000811nqg8rwwmyf', 'EP-UI-THEME-001', 'Theme and Branding Modernization', 'Create a resilient theme-system foundation with configurable color and branding presets from a curated set of company styles.', 'open', '2026-03-14 06:33:59.064', '2026-03-14 06:33:59.064') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmpy9s0s000911nqh718anko', 'EP-UI-A11Y-001', 'Dark Theme Usability and Accessibility Policy', 'Establish and enforce WCAG 2.1 AA contrast standards, minimum font sizes, and surface separation rules for the platform dark theme.', 'in-progress', '2026-03-14 06:33:59.068', '2026-03-14 06:33:59.068') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmpy9s08000411nqwi7okyzx', 'EP-AI-PROVIDERS-001', 'AI Provider Registry, Expanded Providers, and Local AI OOTB', 'Restore the AI provider registry, expanded provider support, model discovery and profiling, and Docker/Ollama out-of-the-box workstream.', 'done', '2026-03-14 06:33:59.048', '2026-03-14 14:40:50.52') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmpy9s0c000511nqpp90acyt', 'EP-AI-COWORKER-001', 'AI Agent Co-worker UX', 'Track the route-aware AI co-worker panel, agent routing, messaging, and contextual teammate UX integrated into the portal shell.', 'done', '2026-03-14 06:33:59.052', '2026-03-14 14:40:50.524') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmqfrbzs000b2m58r88ty7jf', 'EP-DEPLOY-001', 'Standalone Docker Deployment with Managed Ollama', 'Single docker compose up brings portal + Postgres + Ollama online. Platform UI manages Docker/Ollama directly with auto-detection of host GPU/RAM and zero-config model selection.', 'open', '2026-03-14 14:43:31.577', '2026-03-14 14:43:31.577') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmqfrc0b000o2m585fpa8ska', 'EP-AGENT-EXEC-001', 'Agent Task Execution with HITL Governance', 'Agents propose real actions (create backlog items, modify products, update EA). Humans approve before execution. Audit-logged via AuthorizationDecisionLog for regulated industry compliance.', 'open', '2026-03-14 14:43:31.596', '2026-03-14 14:43:31.596') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmqun57h0000h4agvwv322bn', 'EP-WORKFORCE-001', 'Unified Human + AI Workforce Management', 'Transform the Employee route into a full workforce view showing both human roles and AI agents as a single team. ADP autonomy levels, RACI-A responsibility matrices, escalation chains, skill taxonomy (SFIA 9 + Agent Skills), and capacity planning per portfolio.', 'open', '2026-03-14 21:40:10.398', '2026-03-14 21:40:10.398') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmqv1u170000jyryahuavh95', 'EP-QUALITY-001', 'Product Quality Feedback and Error Reporting', 'Capture runtime errors, user-reported issues, and page feedback. Route to the responsible digital product owner via the taxonomy. AI co-worker assists with error context and reporting. Every page has a feedback option.', 'open', '2026-03-14 21:51:35.756', '2026-03-14 21:51:35.756') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmqfrbz300002m58d1u5nlkb', 'EP-LLM-LIVE-001', 'Live LLM Conversations', 'Replace canned responses in the co-worker panel with real AI inference via configured providers. Generalizes the existing profiling call infrastructure into a chat-capable inference pipeline.', 'in-progress', '2026-03-14 14:43:31.552', '2026-03-14 23:37:55.514') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmqun58w000dh4agr0j0v8sv', 'EP-FINANCE-001', 'Financial Primitives and Budget Management', 'Implement robust finance operations in the platform with ERPNext as the execution engine (multi-business, multi-company), including accounts payable, accounts receivable, payroll, taxes, shopping cart to receivables workflow, and CRM handoff for trainer signup + billing events.', 'open', '2026-03-14 21:40:10.449', '2026-03-15 05:12:02.08') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmrduwu6005uaf4ljun5z4i5', 'EP-BUILD-129F34', 'Student Payment & Registration Flow v1.0.0', NULL, 'open', '2026-03-15 06:38:05.503', '2026-03-15 06:38:05.503') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmrduye60063af4l5djqt85j', 'EP-BUILD-A69429', 'Student Payment & Registration Flow v1.0.0', NULL, 'open', '2026-03-15 06:38:07.519', '2026-03-15 06:38:07.519') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmrw3dvt0000ypqa2x3mtoa4', 'EP-REFACTOR-001', 'Platform Refactoring — Technical Debt Reduction', 'Ongoing refactoring to centralize duplicated patterns, reduce technical debt, and improve maintainability. 20% budget rule: when duplicate patterns are noticed during feature work, log them here.', 'open', '2026-03-15 15:08:33.929', '2026-03-15 15:08:33.929') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmrx9st20000cjh84dczrsgi', 'EP-INTAKE-001', 'Portfolio-Aware Feature Intake', 'Smart intake layer: when a user describes what they want, the agent searches existing portfolio/taxonomy/products for related items, suggests starting points, and decomposes large ideas into feature sets with backlog items.', 'open', '2026-03-15 15:41:32.822', '2026-03-15 15:41:32.822') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmrx9st80001cjh8xxihpicy', 'EP-PARALLEL-001', 'Parallel Feature Execution Engine', 'Multiple FeatureBuilds running concurrently with independent sandboxes, managed by an orchestrator agent. Investment controls (budget ceiling, autonomy level per build). The factory floor.', 'open', '2026-03-15 15:41:32.829', '2026-03-15 15:41:32.829') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmrx9std0002cjh8tcfsd2wm', 'EP-AUTONOMY-001', 'Agent Autonomy Controls', 'UX dial for human involvement level per build. Ranges from full HITL (approve every action) to full autonomy (spend limits only). Ties into ADP governance levels from EP-WORKFORCE-001.', 'open', '2026-03-15 15:41:32.833', '2026-03-15 15:41:32.833') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmrx9sth0003cjh8w2w5pzcj', 'EP-CODEGEN-001', 'Build Studio Code Generation Tools', 'MCP tools for sandbox code generation: generate schema, UI components, API routes. Testing + verification tools: run tests, type-check, lint. The backend muscle for the Build Studio.', 'open', '2026-03-15 15:41:32.837', '2026-03-15 15:41:32.837') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmrx9stl0004cjh8ns7ar9jp', 'EP-DEPLOY-002', 'Build Studio Deployment Pipeline', 'Apply sandbox changes to running platform: migrations, code deployment, rollback. Audit trail for every deployment action. Regulated-industry compliance controls.', 'open', '2026-03-15 15:41:32.841', '2026-03-15 15:41:32.841') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmrxkjly00006yvptn1inga9', 'EP-DEDUP-001', 'Duplicate Detection + Cross-Team Collaboration', 'When a user proposes a new feature or product, the platform checks existing builds, backlog items, epics, and registered third-party products across the entire enterprise for overlap. Connects users working on similar initiatives. Suggests reuse of existing products or containers. Prevents organizational duplication at scale. Depends on portfolio taxonomy, product inventory, and EA model being populated.', 'open', '2026-03-15 15:49:54.119', '2026-03-15 15:49:54.119') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmmrzjncl0000ksrteph6xcx4', 'EP-EMP-WS-001', 'Employee Workspace Interaction Model', 'Make the default employee workspace the shared front door for all employees, with role-aware provider, consumer, and collaboration modes. Employees should use one portal shell while seeing different work, services, apps, and handoffs based on role and current responsibilities.
INSERT INTO public."Epic" VALUES ('cmmqpm5na0000tz62vw4tl0sm', 'EP-SELF-DEV-001', 'AI-Driven Platform Self-Development', 'Enable the platform to write new functionality for non-developers. AI agents propose code changes, create components, and deploy updates through governed workflows with human approval. The platform iterates on itself within the 4 portfolio contexts.
INSERT INTO public."Epic" VALUES ('cmms3wmov0000gq0eiljpopv3', 'EP-UPLOAD-001', 'File Upload + Document Parsing for Build Studio', 'Upload spreadsheets, docs, emails, PDFs during feature intake. Agent parses documents to extract structure (columns, fields, processes). Files attached to FeatureBuilds and linked to backlog items. Airtable-style upload-to-data-model flow.', 'open', '2026-03-15 18:47:15.679', '2026-03-15 18:47:15.679') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmms5zoii0000148jak0lterh', 'EP-MCP-001', 'MCP Server Registry + Marketplace Integration', 'Visible MCP server configurations in AI Workforce UX. Browse/install tools from MCP marketplaces. Each agent shows which MCP tools it has access to. Admin can enable/disable/configure MCP servers per agent or globally. Future: community marketplace for sharing custom tools.', 'open', '2026-03-15 19:45:37.242', '2026-03-15 19:45:37.242') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmms820370000trledwv0l6wd', 'EP-PROCESS-001', 'Process Improvement AI Observer', 'A background AI coworker that observes human/agent dialog across all conversations. Identifies friction, repeated questions, failed tool calls, missed context, and UX gaps. Automatically creates backlog items in the correct product backlog with proper context. Core MVP capability for iterative platform improvement. Not a separate UI — runs silently and surfaces findings through the backlog system.', 'open', '2026-03-15 20:43:24.788', '2026-03-15 20:43:24.788') ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('eb7dcd8a-fa15-46c3-854c-811a2fab199a', 'EP-CAL-001', 'Calendar Infrastructure — Unified Scheduling & Event System', 'A calendar event framework serving as platform scheduling infrastructure. Subsumes ScheduledJob into a unified CalendarEvent model supporting one-time and recurring events, automated action execution with backlog-based audit trails, role-contextual UX surfaces, and MCP tool exposure for AI coworkers.', 'open', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87') ON CONFLICT DO NOTHING;
