INSERT INTO public."BacklogItem" VALUES ('cmmpym6mx000rwybjdkvict21', 'BI-PROD-009', 'Define dark-theme contrast standards — WCAG AA minimums for dark backgrounds', 'done', 'product', 'Document colour contrast requirements: 4.5:1 for normal text, 3:1 for large text against #0f0f1a and #1a1a2e surfaces. Establish token palette: --dpf-muted (#8888a0, ~5:1), labels (#c0c0d8, ~7:1), secondary (#b0b0c8, ~6:1). No text may use colours below 4.5:1 on dark surfaces.', '2026-03-14 06:43:37.882', '2026-03-14 06:43:37.882', 1, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmpy9s0s000911nqh718anko', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmpym6n0000twybj6klgpf8p', 'BI-PROD-010', 'Establish minimum font-size policy — 10px floor for all UI text', 'done', 'product', 'Audit all inline styles and Tailwind classes. No text element may be smaller than 10px. Form labels: 12px minimum. Form inputs and buttons: 13px minimum. Document in CLAUDE.md and component guidelines.', '2026-03-14 06:43:37.884', '2026-03-14 06:43:37.884', 2, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmpy9s0s000911nqh718anko', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmpym6n4000vwybjjygya8q0', 'BI-PROD-011', 'Audit and remediate existing admin/platform screens for contrast compliance', 'done', 'product', 'Sweep all /platform, /admin, and /ea screens. Replace any remaining #555566 with #8888a0. Bump undersized text. Verify form inputs, buttons, and labels meet the new minimums.', '2026-03-14 06:43:37.888', '2026-03-14 06:43:37.888', 3, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmpy9s0s000911nqh718anko', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmpym6n6000xwybjmwjk2glj', 'BI-PROD-012', 'Create dark-theme development guidelines for future feature work', 'open', 'product', 'Write developer-facing guidelines covering: surface hierarchy rules (bg < surface-1 < surface-2), border contrast, focus indicators, disabled-state contrast, and how to validate with contrast-checker tools. Include in onboarding docs.', '2026-03-14 06:43:37.891', '2026-03-14 06:43:37.891', 4, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmpy9s0s000911nqh718anko', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmpym6n9000zwybj56iz3j3z', 'BI-PROD-013', 'Add UX Accessibility AI Agent (AGT-903) to agent registry', 'open', 'product', 'Register a cross-cutting UX accessibility agent that reviews UI work for WCAG compliance, contrast ratios, font sizing, and dark-theme usability. Agent should be invokable during code review to flag accessibility regressions.', '2026-03-14 06:43:37.893', '2026-03-14 06:43:37.893', 5, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmpy9s0s000911nqh718anko', NULL, 1, NULL) ON CONFLICT DO NOTHING;
