INSERT INTO public."BacklogItem" VALUES ('cmmqfrc00000d2m58afyvpdor', 'BI-DEPLOY-001', 'Create portal Dockerfile and Docker Compose stack', 'open', 'product', 'Multi-stage Dockerfile for Next.js standalone. Compose: portal (port 3000), db (Postgres 16, volume), ollama (GPU passthrough). Auto-run Prisma migrations on startup.', '2026-03-14 14:43:31.584', '2026-03-14 14:43:31.584', 1, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrbzs000b2m58r88ty7jf', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrc02000f2m585hw7sxnl', 'BI-DEPLOY-002', 'Build Docker API client for container management', 'open', 'product', 'Server-side module talking to Docker Engine API via /var/run/docker.sock. Scoped to Ollama container: status, start/stop/restart, pull image. Auth: manage_provider_connections.', '2026-03-14 14:43:31.586', '2026-03-14 14:43:31.586', 2, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrbzs000b2m58r88ty7jf', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrc04000h2m58pqy45lpo', 'BI-DEPLOY-003', 'Add Ollama management UI in platform', 'open', 'product', 'New section in /platform/ai: Ollama container status, start/stop/restart buttons, model list, pull new model by name, delete model, real-time pull progress.', '2026-03-14 14:43:31.588', '2026-03-14 14:43:31.588', 3, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrbzs000b2m58r88ty7jf', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrc05000j2m58bdflayxf', 'BI-DEPLOY-004', 'Implement host capability detection and auto-model selection', 'open', 'product', 'Detect GPU (NVIDIA runtime), RAM. Selection: CPU <8GB -> phi3:mini, CPU 16GB+ -> llama3:8b, GPU 8GB -> llama3:8b, GPU 16GB+ -> llama3:70b-q4. Store as platform config.', '2026-03-14 14:43:31.59', '2026-03-14 14:43:31.59', 4, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrbzs000b2m58r88ty7jf', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrc08000l2m58c66c7z9s', 'BI-DEPLOY-005', 'Auto-pull default model and auto-configure provider on first startup', 'open', 'product', 'Startup: check Ollama reachable -> check models pulled -> if none, pull auto-selected -> set Ollama provider active -> set as default for agent conversations. Zero manual config.', '2026-03-14 14:43:31.592', '2026-03-14 14:43:31.592', 5, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrbzs000b2m58r88ty7jf', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrc09000n2m58ayj6p44h', 'BI-DEPLOY-006', 'Add health check monitoring and status indicators', 'open', 'product', 'Compose health checks on all services. Portal banner when Ollama unreachable. /api/health endpoint for external monitoring.', '2026-03-14 14:43:31.594', '2026-03-14 14:43:31.594', 6, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrbzs000b2m58r88ty7jf', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrc0i000q2m58i9hhfybv', 'BI-EXEC-001', 'Design AgentActionProposal schema', 'open', 'product', 'New Prisma migration. Model: proposalId (unique), threadId FK AgentThread, messageId FK AgentMessage, agentId, actionType enum, parameters Json, status (proposed|approved|rejected|executed|failed), proposedAt, decidedAt, decidedBy userId FK, executedAt, resultEntityId, resultError.', '2026-03-14 14:43:31.603', '2026-03-14 14:43:31.603', 1, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrc0b000o2m585fpa8ska', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrc0k000s2m589vol7l0b', 'BI-EXEC-002', 'Build proposal creation from agent inference', 'open', 'product', 'Parse LLM tool-use responses into AgentActionProposal records. Define tool schemas: create_backlog_item, update_lifecycle, create_ea_element, etc. System prompts include available tools based on user capabilities.', '2026-03-14 14:43:31.605', '2026-03-14 14:43:31.605', 2, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrc0b000o2m585fpa8ska', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrc0m000u2m582ajjyod7', 'BI-EXEC-003', 'Create proposal card rendering in chat UX', 'open', 'product', 'Structured content in AgentMessageBubble for messages with proposals. Card: action type label, key parameters, affected entity. Inline Approve/Reject/Edit buttons. Visual states for approved/rejected.', '2026-03-14 14:43:31.607', '2026-03-14 14:43:31.607', 3, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrc0b000o2m585fpa8ska', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrc0o000w2m58qjwe1r1g', 'BI-EXEC-004', 'Implement proposal execution engine', 'open', 'product', 'On approval: map actionType + parameters to existing server actions (createBacklogItem, etc.). Execute with approving user auth context. Record executedAt, resultEntityId or resultError. Post confirmation in thread.', '2026-03-14 14:43:31.609', '2026-03-14 14:43:31.609', 4, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrc0b000o2m585fpa8ska', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrc0q000y2m58q69k502u', 'BI-EXEC-005', 'Wire approval events into AuthorizationDecisionLog', 'open', 'product', 'Every proposal approval/rejection writes to AuthorizationDecisionLog: actorRef (who), actionKey (what), objectRef (entity), decision, rationale. Satisfies regulated industry audit trail requirement.', '2026-03-14 14:43:31.611', '2026-03-14 14:43:31.611', 5, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrc0b000o2m585fpa8ska', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrc0s00102m58hb2mor4t', 'BI-EXEC-006', 'Add agent action history view in platform', 'open', 'product', 'Table of AgentActionProposal records in /platform or /admin. Filter by status, agent, action type, date range. Detail view with full parameters, approval chain, execution result. Export for compliance audits.', '2026-03-14 14:43:31.612', '2026-03-14 14:43:31.612', 6, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrc0b000o2m585fpa8ska', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrbzj00042m58a2mu4fk6', 'BI-LLM-002', 'Define agent system prompts for all 9 route agents', 'done', 'product', 'Extend RouteAgentEntry and AgentInfo types with systemPrompt field. Add prompts to ROUTE_AGENT_MAP for each of the 9 route agents describing role, capabilities, and context awareness.', '2026-03-14 14:43:31.567', '2026-03-14 23:37:55.485', 2, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrbz300002m58d1u5nlkb', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrbzl00062m58vimxgwx6', 'BI-LLM-003', 'Add platform default provider and model selection', 'done', 'product', 'Add platform-level default provider+model config for agent conversations. Selection UI in /platform/ai with dropdown of active providers and discovered models. rankProvidersByCost (lib/ai-profiling.ts) provides auto-selection fallback.', '2026-03-14 14:43:31.569', '2026-03-14 23:37:55.489', 3, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrbz300002m58d1u5nlkb', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrbzn00082m589b5nqy5j', 'BI-LLM-004', 'Replace canned responses with live inference in sendMessage', 'done', 'product', 'In sendMessage server action: check for active default provider, build messages array (system prompt + last 20 thread messages + user message), call callProvider, persist response. Fall back to generateCannedResponse when no provider active. Token counts logged via TokenUsage, not stored on AgentMessage.', '2026-03-14 14:43:31.571', '2026-03-14 23:37:55.492', 4, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrbz300002m58d1u5nlkb', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrbzp000a2m58vjzdvjzf', 'BI-LLM-005', 'Wire token usage logging into inference calls', 'done', 'product', 'Extract private logTokenUsage from lib/actions/ai-providers.ts to shared module. Call after every successful inference with agentId, providerId, contextKey=coworker, token counts, and computed cost.', '2026-03-14 14:43:31.573', '2026-03-14 23:37:55.494', 5, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrbz300002m58d1u5nlkb', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqun595000fh4ag0hxg1hrs', 'BI-FIN-001', 'ERPNext deployment and connector platform (multi-company, multi-entity)', 'open', 'product', 'Add platform-hosted ERPNext connector foundation with secure credential handling, connection health checks, and tenant-aware company scoping for two-business operations.', '2026-03-14 21:40:10.458', '2026-03-15 05:12:02.08', 1, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqun58w000dh4agr0j0v8sv', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqp7ujr000189tdmbyn2s61', 'BI-DEPLOY-008', 'First-time setup wizard guided by AI Coworker', 'open', 'product', 'After initial install, the AI Coworker (already running via Ollama) guides the user through first-time setup conversationally: company name, admin password, branding, portfolio preferences. Replaces a traditional form wizard with a natural conversation. The coworker explains each step and why it matters.', '2026-03-14 19:08:18.663', '2026-03-14 19:08:18.663', 8, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqfrbzs000b2m58r88ty7jf', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqp7ujw000389tdq63o5hj1', 'BI-DEPLOY-009', 'Web-hosted SaaS deployment (cloud-hosted option)', 'open', 'product', 'Cloud-hosted deployment option where users sign up and get a running instance without local installation. Local AI is optional/additive. Kubernetes or managed container deployment to a cloud provider.', '2026-03-14 19:08:18.669', '2026-03-14 19:08:18.669', 9, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqfrbzs000b2m58r88ty7jf', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqp7uk0000589tdoc87jxzb', 'BI-DEPLOY-010', 'Mac installer (.dmg or shell script)', 'open', 'product', 'Extend the zero-prerequisites installer to macOS. Detect and install Docker Desktop for Mac, handle Apple Silicon vs Intel, same guided experience as Windows.', '2026-03-14 19:08:18.672', '2026-03-14 19:08:18.672', 10, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqfrbzs000b2m58r88ty7jf', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqp7uk2000789tduzuvpp69', 'BI-DEPLOY-011', 'Linux installer (shell script)', 'open', 'product', 'Extend the zero-prerequisites installer to Linux. Install Docker Engine directly (no Docker Desktop needed). Support Ubuntu/Debian and RHEL/Fedora.', '2026-03-14 19:08:18.675', '2026-03-14 19:08:18.675', 11, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqfrbzs000b2m58r88ty7jf', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqpm5np0002tz6220e8kapy', 'BI-SELFDEV-001', 'Code generation agent with sandboxed execution environment', 'open', 'product', 'Agent can generate code (components, server actions, schema changes) in a sandboxed environment. Preview changes before they affect the running platform. Requires container-based build/test isolation.', '2026-03-14 19:19:26.245', '2026-03-14 19:19:26.245', 1, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqpm5na0000tz62vw4tl0sm', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqpm5nu0004tz62rmokd7ux', 'BI-SELFDEV-002', 'Visual feature builder for non-developers', 'open', 'product', 'Conversational interface where a business user describes what they need ("I need a customer feedback form") and the AI agent builds it. User sees a preview, approves, and it goes live. No code knowledge required.', '2026-03-14 19:19:26.25', '2026-03-14 19:19:26.25', 2, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqpm5na0000tz62vw4tl0sm', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqpm5nx0006tz62d3eub7wj', 'BI-SELFDEV-003', 'Governed code deployment pipeline with HITL approval', 'open', 'product', 'Code changes proposed by agents go through the same HITL governance as data changes (EP-AGENT-EXEC-001). Diff review, automated tests, human approval before merge. Audit trail for compliance.', '2026-03-14 19:19:26.254', '2026-03-14 19:19:26.254', 3, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqpm5na0000tz62vw4tl0sm', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqun5840002h4agy8jxwqwh', 'BI-WF-001', 'Unified workforce view showing humans and AI agents together', 'open', 'product', 'Transform /employee from a role registry into a workforce dashboard. Show human roles with headcount alongside AI agents with tier/capability. Each portfolio shows its combined workforce: human FTEs + agent capacity.', '2026-03-14 21:40:10.42', '2026-03-14 21:40:10.42', 1, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqun57h0000h4agvwv322bn', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqun58a0004h4aguur0lzkc', 'BI-WF-002', 'ADP autonomy levels on agent profiles (A1-A5)', 'open', 'product', 'Adopt OpenAgentGovernance ADP vocabulary. Add adpAutonomyLevel (A1 fully supervised through A5 fully autonomous) and adpDecisionType (D1 operational through D4 self-modification) to agent registry. Positions platform for EU AI Act compliance.', '2026-03-14 21:40:10.426', '2026-03-14 21:40:10.426', 2, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqun57h0000h4agvwv322bn', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqun58f0006h4aggfqdcsxb', 'BI-WF-003', 'RACI-A responsibility matrix per capability', 'open', 'product', 'For each CapabilityKey, show which human role is Accountable (always human, never agent), which agents Execute, which roles are Consulted and Informed. Surface in governance and employee views.', '2026-03-14 21:40:10.432', '2026-03-14 21:40:10.432', 3, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqun57h0000h4agvwv322bn', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqun58j0008h4agxxb9fuqm', 'BI-WF-004', 'Escalation chain: handoff-to-human and cross-agent referral', 'open', 'product', 'Add two new escalation outcomes to governance-resolver: escalate_to_human (agent confidence too low) and handoff_to_agent (cross-specialist referral with context transfer). New EscalationRecord model.', '2026-03-14 21:40:10.435', '2026-03-14 21:40:10.435', 4, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqun57h0000h4agvwv322bn', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqun58n000ah4ag3qpa17no', 'BI-WF-005', 'Agent skill profiles with SFIA 9 codes', 'open', 'product', 'Extend agent registry with AgentSkillProfile: sfiaSkillCode (e.g. ARCH, PROG, USEV), executionMode (autonomous/collaborative/advisory), maxRiskBand. SFIA 9 bridges human and agent skill taxonomies.', '2026-03-14 21:40:10.439', '2026-03-14 21:40:10.439', 5, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqun57h0000h4agvwv322bn', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqun58s000ch4agdzyjarel', 'BI-WF-006', 'Portfolio workforce capacity planning (human FTE + agent equivalent)', 'open', 'product', 'Add configurable fteEquivalentMultiplier per agent tier. Compute Effective Workforce Capacity per portfolio: human role headcount + (agent count * multiplier). Surface in portfolio health dashboard.', '2026-03-14 21:40:10.444', '2026-03-14 21:40:10.444', 6, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqun57h0000h4agvwv322bn', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqun599000hh4ag34mxsvh5', 'BI-FIN-002', 'Procure-to-pay and vendor/AP processing', 'open', 'product', 'Implement invoice capture from ERPNext: supplier onboarding, bill entry, payment run, and tax withholding rules; include PO/expense-to-payable reconciliation where applicable.', '2026-03-14 21:40:10.462', '2026-03-15 05:12:02.08', 2, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqun58w000dh4agr0j0v8sv', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqpm5o00008tz62gggoa0rx', 'BI-SELFDEV-004', 'Platform self-update and version management', 'open', 'product', 'The platform can pull updates from the repository, apply migrations, install or upgrade managed runtimes, and restart itself. Every downloaded or managed runtime must register in inventory and, when employee-facing or employee-operated, create or link a DigitalProduct record in the correct for_employees portfolio context. Version rollback if something breaks. Non-technical admin can trigger updates from the platform UI.', '2026-03-14 19:19:26.257', '2026-03-15 06:02:14.577', 4, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqpm5na0000tz62vw4tl0sm', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqv1u1t0002jyrynyvuo26w', 'BI-QUAL-001', 'Error capture API and QualityIssue model', 'open', 'product', 'New Prisma model: QualityIssue with type (runtime_error | user_report | feedback), route context, user, timestamp, error stack/description, linked digitalProductId and portfolioId (resolved via taxonomy). Lightweight POST /api/quality/report endpoint. Client-side error boundary catches unhandled exceptions and posts automatically.', '2026-03-14 21:51:35.778', '2026-03-14 21:51:35.778', 1, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqv1u170000jyryahuavh95', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqv1u210004jyry85mz7dnr', 'BI-QUAL-002', 'Replace red toast with platform-aware error notification', 'open', 'product', 'Custom Next.js error boundary that captures the error, posts to the quality API, and shows a user-friendly notification: Something went wrong. The platform team has been notified. Include the route, timestamp, and responsible owner name.', '2026-03-14 21:51:35.785', '2026-03-14 21:51:35.785', 2, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqv1u170000jyryahuavh95', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqv1u240006jyry0rdyz6uk', 'BI-QUAL-003', 'Feedback button on every page', 'open', 'product', 'Persistent feedback trigger (small icon near the AI Coworker FAB or in the footer). Opens a lightweight form: type (bug/suggestion/question), description, optional screenshot. Posts to the same QualityIssue model. Route context and user auto-populated.', '2026-03-14 21:51:35.789', '2026-03-14 21:51:35.789', 3, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqv1u170000jyryahuavh95', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqv1u280008jyry4dge1a1i', 'BI-QUAL-004', 'AI co-worker error detection and assisted reporting', 'open', 'product', 'When a runtime error occurs, the AI co-worker detects it and offers to help: I noticed an error. Would you like me to report it with context? Agent captures route, recent actions, error details and creates a structured QualityIssue with richer context than manual report.', '2026-03-14 21:51:35.793', '2026-03-14 21:51:35.793', 4, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqv1u170000jyryahuavh95', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqv1u2d000ajyry679whj5w', 'BI-QUAL-005', 'Quality dashboard for product owners', 'open', 'product', 'Route owners (resolved via taxonomy -> portfolio -> owner role) see a quality dashboard: open issues, error trends, user feedback for their products. Filterable by type, severity, date range. Surface in portfolio and ops views alongside backlog items.', '2026-03-14 21:51:35.798', '2026-03-14 21:51:35.798', 5, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqv1u170000jyryahuavh95', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqv1u2i000cjyryc790qp0o', 'BI-QUAL-006', 'Auto-link errors to digital product via route-to-taxonomy mapping', 'open', 'product', 'Map routes to digital products via existing taxonomy structure. Error on /ea/views/123 resolves to EA portfolio, finds owning digital product, attributes QualityIssue. Responsible employee (portfolio owner role) is notified.', '2026-03-14 21:51:35.802', '2026-03-14 21:51:35.802', 6, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqv1u170000jyryahuavh95', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqvou4c0001118xw8e21s92', 'BI-REST-063', 'Add optional SMS delivery adapter for password recovery', 'open', 'portfolio', 'Extend the token-based password reset workflow with an optional SMS delivery channel behind a provider adapter. Keep email and admin-issued manual recovery as the primary MVP paths. SMS must be explicitly configured, use one-time expiring tokens, preserve neutral user messaging, and support future provider-backed delivery, audit, phone verification, consent, and rate limiting. Evaluate provider cost and compliance requirements before enabling beyond local test environments.', '2026-03-14 22:09:28.956', '2026-03-14 22:09:28.956', 4, NULL, NULL, 'cmmpy9s0g000611nqxtc86284', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqw4x0e0001wszude2hs67f', 'BI-LLM-006', 'Make coworker threads page-scoped by default', 'open', 'portfolio', 'Change the coworker conversation model so each route or UX surface gets its own thread by default. Keep route-aware agent selection aligned with route-scoped history, prevent prior-page context bleed, and preserve explicit future options for cross-page or portfolio-wide conversations when desired.', '2026-03-14 22:21:59.198', '2026-03-14 22:21:59.198', 6, NULL, NULL, 'cmmqfrbz300002m58d1u5nlkb', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqw4x280003wszu93893262', 'BI-LLM-007', 'Add clear conversation control to coworker dialog', 'open', 'portfolio', 'Add a visible erase or clear control to the coworker panel so a user can reset the current conversation for the active page. The action should clear or archive only the current page-scoped thread, preserve audit expectations for future governance needs, and reset the panel to an empty starting state.', '2026-03-14 22:21:59.264', '2026-03-14 22:21:59.264', 7, NULL, NULL, 'cmmqfrbz300002m58d1u5nlkb', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmqfrbzf00022m5871s77w5c', 'BI-LLM-001', 'Build callProvider generalized inference function', 'done', 'product', 'Extract the private callProviderForProfiling from lib/actions/ai-providers.ts into a shared lib/ai-inference.ts module. Generalize into callProvider(providerId, modelId, messages[], systemPrompt) supporting multi-turn chat. Return { content, inputTokens, outputTokens, inferenceMs }.', '2026-03-14 14:43:31.564', '2026-03-14 23:37:55.41', 1, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'cmmqfrbz300002m58d1u5nlkb', NULL, 1, NULL) ON CONFLICT DO NOTHING;
