INSERT INTO public."BacklogItem" VALUES ('cmmrw3dxf0002ypqaxs92exyk', 'BI-REFACTOR-001', 'Centralize provider HTTP error handling (429, 401, 5xx)', 'open', 'product', 'Extract handleProviderHttpError() utility. Currently 429 auto-disable is duplicated in callWithFailover and callProviderForProfiling. Should also cover testProviderAuth and discoverModelsInternal. One function, one place to maintain.', '2026-03-15 15:08:33.987', '2026-03-15 15:08:33.987', 1, NULL, NULL, 'cmmrw3dvt0000ypqa2x3mtoa4', NULL, 1, NULL) ON CONFLICT DO NOTHING;
