INSERT INTO public."BacklogItem" VALUES ('cmmrw3dxm0006ypqazbijccyz', 'BI-REFACTOR-003', 'Consolidate inline styles to Tailwind classes in agent components', 'open', 'product', 'AgentCoworkerPanel, AgentMessageBubble, and AgentMessageInput use inline style objects while the rest of the codebase uses Tailwind. Migrate for consistency.', '2026-03-15 15:08:33.994', '2026-03-15 15:08:33.994', 3, NULL, NULL, 'cmmrw3dvt0000ypqa2x3mtoa4', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('e91663c3-1dd8-4578-a6de-243c33424e58', 'BI-SELFDEV-005', 'Automatic runtime inventory, digital product, and deployment registration', 'open', 'product', 'Ensure install, download, upgrade, and managed-runtime flows automatically register runtimes in inventory, link or create the corresponding Digital Product, and maintain instance-level deployment records per environment. Capture observed footprint, deployment endpoints, and placeholder governance state for resource usage, license review, and pre-production controls so dev sprawl is visible before production.', '2026-03-15 06:02:14.577', '2026-03-15 15:45:08.014', 5, 'cmmpym6lw0001wybjrz1abyry', NULL, 'cmmqpm5na0000tz62vw4tl0sm', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmrxeeur0000o31jpy8uitz8', 'BI-SELFDEV-006', 'Development and production deployment governance placeholders', 'open', 'portfolio', 'Create factory-managed placeholder controls for newly introduced runtimes and external services across Dev and Production. Track resource footprint, licensing basis and review state, ownership, and environment-specific deployment considerations from first introduction so governance starts during development rather than after go-live.', '2026-03-15 15:45:08.019', '2026-03-15 15:45:08.019', NULL, NULL, NULL, 'cmmqpm5na0000tz62vw4tl0sm', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmrzjncl0006ksrtc9e6kjfq', 'BI-EMPWS-006', 'Map workforce roles to workspace defaults and app launches', 'in-progress', 'product', 'Use role and responsibility context to determine which workspace tiles, service cards, launch links, provider panels, and collaboration queues appear by default for each employee.', '2026-03-15 16:45:11.541', '2026-03-15 17:23:45.103', NULL, NULL, NULL, 'cmmrzjncl0000ksrteph6xcx4', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('dbc6994b-9f17-458f-a626-7bee4ff26644', 'BI-SELFDEV-007', 'Require workspace exposure metadata during runtime onboarding', 'done', 'product', 'Extend recursive build and managed runtime onboarding so every downloaded or provisioned runtime records workspace exposure, provider/consumer ownership, app launches, and governance placeholders alongside inventory and digital product registration.', '2026-03-15 16:52:49.666', '2026-03-15 17:33:24.838', 7, NULL, NULL, 'cmmqpm5na0000tz62vw4tl0sm', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmrzjncl0002ksrtbkr81aqx', 'BI-EMPWS-002', 'Build role-aware default workspace sections', 'done', 'product', 'Evolve the default workspace into sections such as My Work, My Services, Services I Provide, and My Apps. Section visibility and ordering should adapt by role and active responsibilities without creating separate workspace shells.', '2026-03-15 16:45:11.541', '2026-03-15 17:33:24.838', NULL, NULL, NULL, 'cmmrzjncl0000ksrteph6xcx4', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmrzjncl0004ksrt3v2o5od1', 'BI-EMPWS-004', 'Expose provider and consumer entry points for digital products', 'done', 'product', 'Each employee-facing digital product must be able to expose both consumer and provider entry points in the workspace. Finance is the first example: finance staff use provider tools while all employees access finance services through the same workspace shell.', '2026-03-15 16:45:11.541', '2026-03-15 17:33:24.838', NULL, NULL, NULL, 'cmmrzjncl0000ksrteph6xcx4', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmmrzjncl0001ksrtejpjxkp9', 'BI-EMPWS-001', 'Define employee interaction modes: consumer, provider, collaborator', 'done', 'portfolio', 'Model employees as people who may consume services, provide services, and collaborate across functions at the same time. The workspace must support multiple interaction modes for the same person instead of splitting departments into separate portals.', '2026-03-15 16:45:11.541', '2026-03-15 17:33:24.838', NULL, NULL, NULL, 'cmmrzjncl0000ksrteph6xcx4', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('16d069e1-2c46-495f-932e-c5dc32d3a32f', 'BI-EMPWS-007', 'Define reusable workspace exposure contract for all digital products', 'done', 'product', 'Create the platform-level contract that maps each digital product to workspace sections, interaction modes, role-based entry points, request/status patterns, and app launches so finance is the first consumer rather than a special case.', '2026-03-15 16:52:49.666', '2026-03-15 17:33:24.838', 7, NULL, NULL, 'cmmrzjncl0000ksrteph6xcx4', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmms2llol0001r0c7yy3uhi50', 'BI-REFACTOR-004', 'Refactor Admin page into tabbed sections', 'open', 'product', 'Admin page is getting busy — split into tabs: Users, Branding, Platform Keys, System Settings. Each tab is a focused section.', '2026-03-15 18:10:41.542', '2026-03-15 18:10:41.542', 2, NULL, NULL, 'cmmrw3dvt0000ypqa2x3mtoa4', NULL, 1, NULL) ON CONFLICT DO NOTHING;
