INSERT INTO public."BacklogItem" VALUES ('4abb1c45-d45e-43f4-9afd-ce7ccc713b60', 'BI-CAL-015', 'Backlog: Identity management integration (future)', 'open', 'product', 'Future epic item: update calendar auth model when IdM epic lands. Delegation chains for AI coworker authority, service accounts for system events, scoped authorization beyond role-based.', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 15, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('d96939a7-1747-4cad-8719-3888dfba7625', 'BI-CAL-006', 'Permissions: view_calendar + manage_calendar', 'open', 'product', 'Add view_calendar (all 6 HR roles) and manage_calendar (HR-000, HR-500) to permissions.ts ROLE_CAPABILITIES. Add Calendar nav item to Header.tsx with view_calendar capability gate.', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 6, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('ff1e98e2-aaea-4b87-b502-e0539c33c112', 'BI-CAL-009', 'EventDetailPanel slide panel', 'open', 'product', 'Create apps/web/components/calendar/EventDetailPanel.tsx — reuses BacklogPanel slide pattern. Shows title, description, schedule, execution status, linked backlog item, creator, action payload. Create mode for new events with form validation.', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 9, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('33b2a562-08db-4b81-b458-830931398e81', 'BI-CAL-004', 'Calendar server actions (actions/calendar.ts)', 'open', 'product', 'Create apps/web/lib/actions/calendar.ts with "use server" actions: createCalendarEvent, updateCalendarEvent, cancelCalendarEvent, executeEventAction. Auth gates: manage_calendar for create/update/cancel, plus action-specific permission checks. Execution pipeline: create BacklogItem in-progress, execute action, update to done/failed.', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 4, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('efbb4ee8-4f76-45f8-8d23-f0fba1c162e8', 'BI-CAL-014', 'Backlog: Email notifications on event completion (future)', 'open', 'product', 'Future epic item: optional email to creator when an action event completes or fails. Configurable per-event. Requires email infrastructure.', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 14, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('d4f9a4b4-290e-4c2a-8409-707fa025d330', 'BI-CAL-013', 'Backlog: RFC 5545 RRULE parsing (future)', 'open', 'product', 'Future epic item: implement full iCal RRULE parsing for complex recurrence patterns (every MWF, first Monday of month, exclusion dates, end dates). When implemented, rrule field takes precedence over schedule field.', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 13, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('f8b73797-0e3a-4178-990a-cda06542cf5b', 'BI-CAL-001', 'CalendarEvent schema + migration (drop ScheduledJob)', 'open', 'product', 'Create CalendarEvent model with all fields from spec (eventId, title, eventType, source, status, startsAt/endsAt, allDay, timezone, rrule, schedule, nextRunAt, lastRunAt, actionPayload/Result, assignments, metadata). Add inverse relations on BacklogItem, Agent, User. Widen BacklogItem.type to include "calendar". Migrate existing ScheduledJob records (provider-registry-sync, provider-priority-optimizer) to CalendarEvent. Drop ScheduledJob model.', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 1, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('d8ca1263-b500-4034-a8b0-90106aff6252', 'BI-CAL-008', 'Full calendar route with week grid (/calendar)', 'open', 'product', 'Create apps/web/app/(shell)/calendar/layout.tsx (auth gate: view_calendar) and page.tsx (server component). Build CalendarGrid.tsx (client, CSS Grid week view with day/week/month switcher), CalendarSidebar.tsx (filters by event type, source, role), prev/next/today navigation. Events color-coded by type.', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 8, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('7108dc33-10bd-453f-aca6-c90c82c90c66', 'BI-CAL-003', 'Calendar data fetchers (calendar-data.ts)', 'open', 'product', 'Create apps/web/lib/calendar-data.ts with React cache fetchers: getCalendarEvents(filters), getUpcomingEvents(role, userId, limit), getEventById(eventId). Role-contextual filtering via assignedToRole + assignedToUserId. Admin (HR-000) sees all by default.', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 3, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('f5dec9c7-8ccd-4735-83a9-a088965840c7', 'BI-CAL-002', 'Calendar pure helpers and unit tests (calendar-types.ts)', 'open', 'product', 'Create apps/web/lib/calendar-types.ts with: EVENT_TYPE_COLOURS, STATUS_LABELS, SCHEDULE_INTERVALS_MS (moved from ai-provider-types), validateCalendarInput, computeNextRunAt, formatEventTime. Port schedule helpers from ai-provider-types.ts. Write Vitest tests in calendar-types.test.ts.', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 2, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cff05c78-c39d-4d2d-a325-6f2e5bb33266', 'BI-CAL-010', 'Refactor ScheduledJobsTable to use CalendarEvent', 'open', 'product', 'Update apps/web/components/platform/ScheduledJobsTable.tsx and platform/ai/page.tsx to query CalendarEvent (source: "system", eventType: "action") instead of ScheduledJob. Same inline schedule editing UX. "disabled" toggle maps to status: cancelled/scheduled.', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 10, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('e9fc7339-8673-495d-a336-6320e52b4aa8', 'BI-CAL-011', 'MCP tool: calendar_manage_event', 'open', 'product', 'Expose calendar CRUD as MCP tool for AI coworker consumption. Operations: create, update, cancel, list, get. Auth: inherits user session, createdById set server-side, manage_calendar + action-specific permission checks. Filter support for list operation.', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 11, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('a175b50c-f39c-4ea2-8b9e-e64b605ad10b', 'BI-CAL-005', 'Migrate ScheduledJob references in AI provider code', 'open', 'product', 'Update ai-provider-types.ts (remove ScheduledJob types), ai-provider-data.ts (remove getScheduledJobs), ai-provider-priority.ts (prisma.scheduledJob -> CalendarEvent), ai-provider-internals.ts (prisma.scheduledJob.upsert -> CalendarEvent), actions/agent-coworker.ts (prisma.scheduledJob.deleteMany -> CalendarEvent), actions/ai-providers.ts (remove ScheduledJob actions, delegate to calendar).', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 5, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('817482f0-7b26-4ab2-a433-1921c598d288', 'BI-CAL-012', 'Seed calendar events', 'open', 'product', 'Replace seedScheduledJobs() with seedCalendarEvents() in seed.ts. Seed: EVT-provider-registry-sync (weekly action, system), EVT-provider-priority-optimizer (weekly action, system), EVT-vuln-scan-weekly (weekly action, system, no agent), sample informational event (Platform Maintenance Window).', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 12, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('120238a5-e3c1-4eaa-b8aa-708e5a00151a', 'BI-CAL-016', 'Backlog: Customer-facing calendar (future)', 'open', 'product', 'Future epic item: business-model-dependent customer/partner calendar. Onboarding patterns and configuration for property management fleet scheduling, student class schedules, etc. Requires CustomerAccount scoping.', '2026-03-15 22:47:41.87', '2026-03-15 22:47:41.87', 16, 'cmmpym6lw0001wybjrz1abyry', 'cmmpxy9sm00fizriks6h7x17t', 'eb7dcd8a-fa15-46c3-854c-811a2fab199a', NULL, 1, NULL) ON CONFLICT DO NOTHING;
